import jwt
import datetime

def generate_jwt_token(user_id: str, role: str, secret_key: str, algorithm: str = 'HS256', expires_in_minutes: int = 30) -> str:
    """
    Generates a JWT token for user authentication.

    Args:
        user_id (str): The unique identifier for the user.
        role (str): The role of the user (e.g., 'admin', 'user').
        secret_key (str): The secret key used to sign the JWT.
                          This should be a strong, confidential key.
        algorithm (str): The algorithm to use for signing the JWT (default: 'HS256').
        expires_in_minutes (int): The number of minutes until the token expires (default: 30).

    Returns:
        str: The generated JWT token.
    """
    if not secret_key:
        raise ValueError("secret_key cannot be empty. A strong secret key is required for security.")

    # Define the payload for the JWT
    payload = {
        'user_id': user_id,
        'role': role,
        'exp': datetime.datetime.utcnow() + datetime.timedelta(minutes=expires_in_minutes),
        'iat': datetime.datetime.utcnow()
    }

    # Encode the payload to a JWT token
    token = jwt.encode(payload, secret_key, algorithm=algorithm)
    return token